import{bQ as a,aL as n,u as t,G as p}from"./chunks/framework.D06dwy5q.js";const k=JSON.parse('{"title":"HAProxy","description":"","frontmatter":{},"headers":[],"relativePath":"08.负载均衡与高可用/03-HAProxy.md","filePath":"08.负载均衡与高可用/03-HAProxy.md","lastUpdated":null}'),e={name:"08.负载均衡与高可用/03-HAProxy.md"};function i(l,s,d,h,o,c){return n(),t("div",null,[...s[0]||(s[0]=[p(`<h1 id="haproxy" tabindex="-1">HAProxy <a class="header-anchor" href="#haproxy" aria-label="Permalink to &quot;HAProxy&quot;">​</a></h1><p>HAProxy 常用于四层和七层负载均衡，配置重点在 <code>frontend</code>、<code>backend</code>、健康检查、ACL 路由、会话保持、统计页面和日志。</p><h2 id="一、haproxy-适合做什么" tabindex="-1">一、HAProxy 适合做什么 <a class="header-anchor" href="#一、haproxy-适合做什么" aria-label="Permalink to &quot;一、HAProxy 适合做什么&quot;">​</a></h2><p>HAProxy 是一个专门做代理和负载均衡的服务。它既能代理 TCP，也能代理 HTTP。和 Nginx 相比，HAProxy 的后端健康检查、连接状态、统计页面和七层路由表达更直接。</p><p>常见链路：</p><div class="mermaid-diagram" data-mermaid-code="flowchart%20LR%0A%20%20%20%20client%5B%22%E5%AE%A2%E6%88%B7%E7%AB%AF%22%5D%20--%3E%20haproxy%5B%22HAProxy%22%5D%0A%20%20%20%20haproxy%20--%3E%20backend%5B%22%E5%90%8E%E7%AB%AF%E6%9C%8D%E5%8A%A1%E5%99%A8%E7%BB%84%22%5D%0A"></div><p>几个核心概念：</p><table tabindex="0"><thead><tr><th>概念</th><th>含义</th></tr></thead><tbody><tr><td><code>global</code></td><td>进程级配置，比如日志、进程数、最大连接</td></tr><tr><td><code>defaults</code></td><td>默认参数，给 frontend/backend/listen 继承</td></tr><tr><td><code>frontend</code></td><td>接收客户端请求的入口</td></tr><tr><td><code>backend</code></td><td>后端服务器组</td></tr><tr><td><code>listen</code></td><td>同时包含 frontend 和 backend 的简化写法</td></tr><tr><td>ACL</td><td>按请求内容做匹配和路由</td></tr></tbody></table><p>HAProxy 擅长管 API 和 TCP 入口，Nginx 擅长管静态资源和普通 Web 反代。这不是绝对分工，只是 HAProxy 的状态和后端检查信息更直观。</p><h2 id="二、安装" tabindex="-1">二、安装 <a class="header-anchor" href="#二、安装" aria-label="Permalink to &quot;二、安装&quot;">​</a></h2><p>RHEL / Rocky / CentOS：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">yum</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -y</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> haproxy</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">systemctl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> enable</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --now</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> haproxy</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">haproxy</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -v</span></span></code></pre></div><p>Debian / Ubuntu：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">apt</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> update</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">apt</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -y</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> haproxy</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">systemctl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> enable</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --now</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> haproxy</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">haproxy</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -v</span></span></code></pre></div><p>常见文件：</p><table tabindex="0"><thead><tr><th>路径</th><th>用途</th></tr></thead><tbody><tr><td><code>/etc/haproxy/haproxy.cfg</code></td><td>主配置文件</td></tr><tr><td><code>/var/log/haproxy.log</code></td><td>常见日志目标之一，取决于 rsyslog 配置</td></tr><tr><td><code>/usr/sbin/haproxy</code></td><td>主程序</td></tr><tr><td><code>/run/haproxy/admin.sock</code></td><td>管理 socket，可选</td></tr></tbody></table><p>检查配置：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">haproxy</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -c</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -f</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /etc/haproxy/haproxy.cfg</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  # 只检查配置，不启动</span></span></code></pre></div><h2 id="三、基础-http-负载均衡" tabindex="-1">三、基础 HTTP 负载均衡 <a class="header-anchor" href="#三、基础-http-负载均衡" aria-label="Permalink to &quot;三、基础 HTTP 负载均衡&quot;">​</a></h2><p>示例配置：</p><div class="language-haproxy vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">haproxy</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span># /etc/haproxy/haproxy.cfg</span></span>
<span class="line"><span>global</span></span>
<span class="line"><span>    log 127.0.0.1 local2</span></span>
<span class="line"><span>    maxconn 10000</span></span>
<span class="line"><span>    daemon</span></span>
<span class="line"><span></span></span>
<span class="line"><span>defaults</span></span>
<span class="line"><span>    mode http</span></span>
<span class="line"><span>    log global</span></span>
<span class="line"><span>    option httplog</span></span>
<span class="line"><span>    option dontlognull</span></span>
<span class="line"><span>    option forwardfor</span></span>
<span class="line"><span>    timeout connect 3s</span></span>
<span class="line"><span>    timeout client  30s</span></span>
<span class="line"><span>    timeout server  30s</span></span>
<span class="line"><span></span></span>
<span class="line"><span>frontend web_http</span></span>
<span class="line"><span>    bind *:80</span></span>
<span class="line"><span>    default_backend web_servers</span></span>
<span class="line"><span></span></span>
<span class="line"><span>backend web_servers</span></span>
<span class="line"><span>    balance roundrobin</span></span>
<span class="line"><span>    option httpchk GET /health</span></span>
<span class="line"><span>    server web01 192.168.10.21:80 check</span></span>
<span class="line"><span>    server web02 192.168.10.22:80 check</span></span></code></pre></div><p>关键点：</p><table tabindex="0"><thead><tr><th>配置</th><th>说明</th></tr></thead><tbody><tr><td><code>mode http</code></td><td>按 HTTP 模式处理，能看 Header、URI、状态码</td></tr><tr><td><code>bind *:80</code></td><td>监听 80 端口</td></tr><tr><td><code>default_backend</code></td><td>默认后端组</td></tr><tr><td><code>balance roundrobin</code></td><td>轮询（默认算法）。不写 <code>balance</code> 时就是 <code>roundrobin</code></td></tr><tr><td><code>option httpchk</code></td><td>HTTP 健康检查，不写时 HAProxy 只做 TCP 端口检查</td></tr><tr><td><code>option forwardfor</code></td><td>给后端传递客户端真实 IP</td></tr><tr><td><code>check</code></td><td>对这个后端启用健康检查。不写 <code>check</code> 时 HAProxy 不会主动探测这个后端</td></tr></tbody></table><p>三个 <code>timeout</code> 没有默认值或默认值为 0（表示不超时）——不显式设置的话连接可能永久挂起。<code>timeout connect</code> 控制和后端建立 TCP 连接的超时，<code>timeout client</code> 控制接收客户端请求的超时，<code>timeout server</code> 控制等待后端响应的超时。</p><p>加载：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">haproxy</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -c</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -f</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /etc/haproxy/haproxy.cfg</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">systemctl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> reload</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> haproxy</span></span></code></pre></div><p>验证：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -I</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> http://127.0.0.1/</span></span></code></pre></div><h2 id="四、tcp-负载均衡" tabindex="-1">四、TCP 负载均衡 <a class="header-anchor" href="#四、tcp-负载均衡" aria-label="Permalink to &quot;四、TCP 负载均衡&quot;">​</a></h2><p>TCP 模式适合 MySQL、Redis、普通 TCP 服务这类入口。</p><div class="language-haproxy vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">haproxy</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>frontend mysql_tcp</span></span>
<span class="line"><span>    bind *:3306</span></span>
<span class="line"><span>    mode tcp</span></span>
<span class="line"><span>    default_backend mysql_servers</span></span>
<span class="line"><span></span></span>
<span class="line"><span>backend mysql_servers</span></span>
<span class="line"><span>    mode tcp</span></span>
<span class="line"><span>    balance source</span></span>
<span class="line"><span>    server mysql01 192.168.10.31:3306 check</span></span>
<span class="line"><span>    server mysql02 192.168.10.32:3306 check backup</span></span></code></pre></div><p><code>backup</code> 表示备用后端，普通后端不可用时才接流量。数据库入口要特别谨慎，普通 HAProxy TCP 转发不等于自动处理主从读写角色，后端角色切换要有额外控制。</p><h2 id="五、acl-路由" tabindex="-1">五、ACL 路由 <a class="header-anchor" href="#五、acl-路由" aria-label="Permalink to &quot;五、ACL 路由&quot;">​</a></h2><p>ACL 用来按请求特征选择后端。</p><div class="language-haproxy vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">haproxy</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>frontend web_http</span></span>
<span class="line"><span>    bind *:80</span></span>
<span class="line"><span></span></span>
<span class="line"><span>    acl host_api hdr(host) -i api.example.local</span></span>
<span class="line"><span>    acl path_admin path_beg /admin/</span></span>
<span class="line"><span>    acl path_static path_beg /static/</span></span>
<span class="line"><span></span></span>
<span class="line"><span>    use_backend api_servers if host_api</span></span>
<span class="line"><span>    use_backend admin_servers if path_admin</span></span>
<span class="line"><span>    use_backend static_servers if path_static</span></span>
<span class="line"><span>    default_backend web_servers</span></span></code></pre></div><p>常见匹配：</p><table tabindex="0"><thead><tr><th>ACL</th><th>含义</th></tr></thead><tbody><tr><td><code>hdr(host) -i api.example.local</code></td><td>Host 等于指定域名，忽略大小写</td></tr><tr><td><code>path_beg /api/</code></td><td>路径以 <code>/api/</code> 开头</td></tr><tr><td><code>path_end .jpg .png</code></td><td>路径以指定后缀结束</td></tr><tr><td><code>src 10.0.0.0/8</code></td><td>来源 IP 匹配网段</td></tr></tbody></table><p>ACL 很方便，也容易越写越多。入口层规则开始大量包含业务语义时，发布前要多看一眼配置可读性和回滚方式。</p><h2 id="六、会话保持" tabindex="-1">六、会话保持 <a class="header-anchor" href="#六、会话保持" aria-label="Permalink to &quot;六、会话保持&quot;">​</a></h2><p>按源地址哈希：</p><div class="language-haproxy vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">haproxy</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>backend web_servers</span></span>
<span class="line"><span>    balance source</span></span>
<span class="line"><span>    server web01 192.168.10.21:80 check</span></span>
<span class="line"><span>    server web02 192.168.10.22:80 check</span></span></code></pre></div><p>Cookie 粘性：</p><div class="language-haproxy vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">haproxy</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>backend web_servers</span></span>
<span class="line"><span>    balance roundrobin</span></span>
<span class="line"><span>    cookie SRV insert indirect nocache</span></span>
<span class="line"><span>    server web01 192.168.10.21:80 check cookie web01</span></span>
<span class="line"><span>    server web02 192.168.10.22:80 check cookie web02</span></span></code></pre></div><p>Cookie 方式适合 HTTP 应用，但后端扩缩容、故障摘除时仍然要考虑 session 是否能迁移。粘住后端只能减少漂移，不等于解决会话存储问题。</p><h2 id="七、健康检查" tabindex="-1">七、健康检查 <a class="header-anchor" href="#七、健康检查" aria-label="Permalink to &quot;七、健康检查&quot;">​</a></h2><p>HTTP 健康检查：</p><div class="language-haproxy vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">haproxy</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>backend web_servers</span></span>
<span class="line"><span>    option httpchk GET /health</span></span>
<span class="line"><span>    http-check expect status 200</span></span>
<span class="line"><span>    server web01 192.168.10.21:80 check inter 2s fall 3 rise 2</span></span>
<span class="line"><span>    server web02 192.168.10.22:80 check inter 2s fall 3 rise 2</span></span></code></pre></div><p>参数说明：</p><table tabindex="0"><thead><tr><th>参数</th><th>含义</th></tr></thead><tbody><tr><td><code>inter 2s</code></td><td>每 2 秒检查一次</td></tr><tr><td><code>fall 3</code></td><td>连续失败 3 次认为不可用</td></tr><tr><td><code>rise 2</code></td><td>连续成功 2 次认为恢复</td></tr><tr><td><code>http-check expect status 200</code></td><td>期望 HTTP 200</td></tr></tbody></table><p>健康检查路径要稳定、轻量。把数据库复杂查询放进去，会让 HAProxy 的检查也参与制造压力。</p><h2 id="八、统计页面" tabindex="-1">八、统计页面 <a class="header-anchor" href="#八、统计页面" aria-label="Permalink to &quot;八、统计页面&quot;">​</a></h2><p>开启 stats：</p><div class="language-haproxy vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">haproxy</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>listen stats</span></span>
<span class="line"><span>    bind *:8404</span></span>
<span class="line"><span>    mode http</span></span>
<span class="line"><span>    stats enable</span></span>
<span class="line"><span>    stats uri /stats</span></span>
<span class="line"><span>    stats refresh 10s</span></span>
<span class="line"><span>    stats auth admin:strong_password_here</span></span></code></pre></div><p>访问：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>http://192.168.10.10:8404/stats</span></span></code></pre></div><p>统计页能看到前后端状态、连接数、响应状态、健康检查结果。生产里这个端口只放给内网或运维网段，不放公网。</p><h2 id="九、日志" tabindex="-1">九、日志 <a class="header-anchor" href="#九、日志" aria-label="Permalink to &quot;九、日志&quot;">​</a></h2><p>HAProxy 常把日志交给 syslog。配置里：</p><div class="language-haproxy vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">haproxy</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>global</span></span>
<span class="line"><span>    log 127.0.0.1 local2</span></span>
<span class="line"><span></span></span>
<span class="line"><span>defaults</span></span>
<span class="line"><span>    log global</span></span>
<span class="line"><span>    option httplog</span></span></code></pre></div><p>这里的 <code>127.0.0.1 local2</code> 表示 HAProxy 把日志发给本机 syslog，并使用 <code>local2</code> 这个 facility。rsyslog 要有对应接收和落盘规则，不然 HAProxy 配了日志也可能看不到文件。</p><p>rsyslog 示例：</p><div class="language-conf vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">conf</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span># /etc/rsyslog.d/haproxy.conf</span></span>
<span class="line"><span>local2.* /var/log/haproxy.log</span></span></code></pre></div><p>如果系统没有打开 UDP syslog 接收，可以补上本机 UDP 监听：</p><div class="language-conf vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">conf</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span># /etc/rsyslog.d/haproxy-udp.conf</span></span>
<span class="line"><span>module(load=&quot;imudp&quot;)</span></span>
<span class="line"><span>input(type=&quot;imudp&quot; port=&quot;514&quot;)</span></span></code></pre></div><p>重启日志服务：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">systemctl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> restart</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> rsyslog</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">systemctl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> reload</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> haproxy</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">tail</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -f</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /var/log/haproxy.log</span></span></code></pre></div><p>日志里会有前端、后端、状态码和耗时。接口超时时，先看 HAProxy 日志里的排队时间、连接时间、响应时间，再看后端应用日志。如果日志文件一直没有内容，先看 rsyslog 是否接到了 <code>local2</code>，再看 HAProxy 配置是否真的 reload 成功。</p><h2 id="十、管理-socket" tabindex="-1">十、管理 socket <a class="header-anchor" href="#十、管理-socket" aria-label="Permalink to &quot;十、管理 socket&quot;">​</a></h2><p>管理 socket 用来在命令行查看和调整 HAProxy 运行状态。普通环境只开 stats 页面也够用，但排查后端状态、临时下线节点时，socket 更直接。</p><p>在 <code>global</code> 里开启：</p><div class="language-haproxy vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">haproxy</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>global</span></span>
<span class="line"><span>    stats socket /run/haproxy/admin.sock mode 660 level admin</span></span>
<span class="line"><span>    stats timeout 30s</span></span></code></pre></div><p>查看信息：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">echo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;show info&quot;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> socat</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> -</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /run/haproxy/admin.sock</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">echo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;show stat&quot;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> socat</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> -</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /run/haproxy/admin.sock</span></span></code></pre></div><p>这个 socket 有管理权限，文件权限要收紧。线上临时摘后端可以通过 socket 做，但操作记录要能查到，不然事后很难确认当时谁把哪台节点切下去了。</p><h2 id="十一、常见排查" tabindex="-1">十一、常见排查 <a class="header-anchor" href="#十一、常见排查" aria-label="Permalink to &quot;十一、常见排查&quot;">​</a></h2><p>常用命令：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">haproxy</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -c</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -f</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /etc/haproxy/haproxy.cfg</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">systemctl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> status</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> haproxy</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --no-pager</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ss</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -lntp</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> grep</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> haproxy</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">tail</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -f</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /var/log/haproxy.log</span></span></code></pre></div><p>常见问题：</p><table tabindex="0"><thead><tr><th>现象</th><th>客户端看到什么</th><th>排查方向</th></tr></thead><tbody><tr><td>配置加载失败</td><td>服务启动失败或 reload 不生效</td><td><code>haproxy -c -f</code> 检查语法、缩进、关键字位置</td></tr><tr><td>503 Service Unavailable</td><td>浏览器/curl 收到 503，HAProxy 没有可用后端</td><td>后端全被摘除、backend 没可用 server</td></tr><tr><td>504 Gateway Timeout</td><td>浏览器/curl 收到 504，请求卡到超时</td><td>后端响应太慢或未在 <code>timeout server</code> 内返回</td></tr><tr><td>健康检查失败</td><td>stats 页面后端变红 DOWN</td><td>健康检查路径不对、状态码不对、防火墙</td></tr><tr><td>只有一台后端有流量</td><td>多后端但请求只打一台</td><td>会话保持、权重偏斜、长连接复用</td></tr><tr><td>真实 IP 丢失</td><td>后端日志里来源 IP 都是 HAProxy 地址</td><td>没开 <code>option forwardfor</code> 或后端未信任代理</td></tr></tbody></table><p>查看后端状态最直观的是 stats 页面。命令行里也可以通过 socket 做管理，但普通环境先把 stats 和日志配好就够用。</p>`,80)])])}const g=a(e,[["render",i]]);export{k as __pageData,g as default};
